diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index bd225bcc0635..39d464812939 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1388,9 +1388,8 @@ public:
   ~ScalarizationResult() {
     assert(!ToFreeze && "freeze() not called with ToFreeze being set");
   }
-
-  static ScalarizationResult unsafe() { return {StatusTy::Unsafe}; }
   static ScalarizationResult safe() { return {StatusTy::Safe}; }
+  static ScalarizationResult unsafe() { return {StatusTy::Unsafe}; }
   static ScalarizationResult safeWithFreeze(Value *ToFreeze) {
     return {StatusTy::SafeWithFreeze, ToFreeze};
   }
@@ -1446,9 +1445,16 @@ static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,
   }

   unsigned IntWidth = Idx->getType()->getScalarSizeInBits();
-  APInt Zero(IntWidth, 0);
-  APInt MaxElts(IntWidth, NumElements);
-  ConstantRange ValidIndices(Zero, MaxElts);
+  // Build the range of valid indices: [0, NumElements).
+  // If NumElements does not fit in the index type (e.g., NumElements >= 2^IntWidth),
+  // then any representable index value is in-bounds. In that case, avoid constructing
+  // an APInt with a too-large value and treat the valid range as the full unsigned range.
+  ConstantRange ValidIndices(IntWidth, true); // start with full range
+  if (NumElements < (IntWidth >= 64 ? UINT64_MAX : (1ULL << IntWidth))) {
+    APInt Zero = APInt::getZero(IntWidth);
+    APInt MaxElts(IntWidth, NumElements);
+    ValidIndices = ConstantRange(Zero, MaxElts);
+  }
   ConstantRange IdxRange(IntWidth, true);

   if (isGuaranteedNotToBePoison(Idx, &AC)) {
@@ -1508,44 +1514,48 @@ bool VectorCombine::foldSingleElementStore(Instruction &I) {
              m_InsertElt(m_Instruction(Source), m_Value(NewElement),
                          m_Value(Idx))))
     return false;
+    if (auto *Load = dyn_cast<LoadInst>(Source)) {
+      auto VecTy = cast<VectorType>(SI->getValueOperand()->getType());
+      Value *SrcAddr = Load->getPointerOperand()->stripPointerCasts();
+      if (!Load->isSimple() || !DL->typeSizeEqualsStoreSize(Load->getType()->getScalarType()) ||
+          Load->getParent() != SI->getParent() || SrcAddr != SI->getPointerOperand()->stripPointerCasts())
+        return false;

-  if (auto *Load = dyn_cast<LoadInst>(Source)) {
-    auto VecTy = cast<VectorType>(SI->getValueOperand()->getType());
-    Value *SrcAddr = Load->getPointerOperand()->stripPointerCasts();
-    // Don't optimize for atomic/volatile load or store. Ensure memory is not
-    // modified between, vector type matches store size, and index is inbounds.
-    if (!Load->isSimple() || Load->getParent() != SI->getParent() ||
-        !DL->typeSizeEqualsStoreSize(Load->getType()->getScalarType()) ||
-        SrcAddr != SI->getPointerOperand()->stripPointerCasts())
-      return false;
+      auto ScalarizableIdx = canScalarizeAccess(VecTy, Idx, Load, AC, DT);
+      if (ScalarizableIdx.isUnsafe() ||
+          isMemModifiedBetween(Load->getIterator(), SI->getIterator(),
+                               MemoryLocation::get(SI), AA))
+        return false;

-    auto ScalarizableIdx = canScalarizeAccess(VecTy, Idx, Load, AC, DT);
-    if (ScalarizableIdx.isUnsafe() ||
-        isMemModifiedBetween(Load->getIterator(), SI->getIterator(),
-                             MemoryLocation::get(SI), AA))
-      return false;
+      // Ensure we add the load back to the worklist BEFORE its users so they can
+      // be erased in the correct order.
+      Worklist.push(Load);

-    // Ensure we add the load back to the worklist BEFORE its users so they can
-    // erased in the correct order.
-    Worklist.push(Load);
-
-    if (ScalarizableIdx.isSafeWithFreeze())
-      ScalarizableIdx.freeze(Builder, *cast<Instruction>(Idx));
-    Value *GEP = Builder.CreateInBoundsGEP(
-        SI->getValueOperand()->getType(), SI->getPointerOperand(),
-        {ConstantInt::get(Idx->getType(), 0), Idx});
-    StoreInst *NSI = Builder.CreateStore(NewElement, GEP);
-    NSI->copyMetadata(*SI);
-    Align ScalarOpAlignment = computeAlignmentAfterScalarization(
-        std::max(SI->getAlign(), Load->getAlign()), NewElement->getType(), Idx,
-        *DL);
-    NSI->setAlignment(ScalarOpAlignment);
-    replaceValue(I, *NSI);
-    eraseInstruction(I);
-    return true;
-  }
+      if (ScalarizableIdx.isSafeWithFreeze()) {
+        if (auto *UserI = dyn_cast<Instruction>(Idx)) {
+          ScalarizableIdx.freeze(Builder, *UserI);
+        } else {
+          ScalarizableIdx.discard();
+          return false;
+        }
+      }
+      Value *GEP = Builder.CreateInBoundsGEP(
+          SI->getValueOperand()->getType(), SI->getPointerOperand(),
+          {ConstantInt::get(Idx->getType(), 0), Idx});
+      StoreInst *NSI = Builder.CreateStore(NewElement, GEP);
+      NSI->copyMetadata(*SI);
+      Align ScalarOpAlignment = computeAlignmentAfterScalarization(
+          std::max(SI->getAlign(), Load->getAlign()), NewElement->getType(), Idx, *DL);
+      NSI->setAlignment(ScalarOpAlignment);
+      replaceValue(I, *NSI);
+      eraseInstruction(I);
+      return true;
+    }
+
+    return false;

   return false;
+  return false;
 }

